class Solution {
    public String largestMerge(String word1, String w2) {
        StringBuilder sb = new StringBuilder();
        int i = 0, j = 0;
        while (i < word1.length() || j < w2.length()) {
            if (i < word1.length() && (j == w2.length() || word1.charAt(i) > w2.charAt(j))) {
                sb.append(word1.charAt(i++));
            } else {
                sb.append(w2.charAt(j++));
            }
        }
        return sb.toString();
    }
}
